function initRealtorCa() {
  console.log("[PropFlow] Realtor.ca content script initializing");
  setupDebugHelper();
  chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
    console.log("[PropFlow] Realtor.ca content script received message:", message.type);
    const isListingPage2 = isRealtorCaListingPage();
    const isMapPage2 = isRealtorCaMapPage();
    const isSavedSearchesPage2 = isRealtorCaSavedSearchesPage();
    if (message.type === "PROPFLOW_PING") {
      console.log("[PropFlow] PING received, sending PONG");
      sendResponse({
        ready: true,
        hostname: window.location.hostname,
        isListingPage: isListingPage2,
        isMapPage: isMapPage2,
        isSavedSearchesPage: isSavedSearchesPage2
      });
      return true;
    }
    if (message.type === "PROPFLOW_START_BULK_SCRAPE") {
      console.log("[PropFlow] Starting bulk scrape with data:", message.data);
      handleBulkScrapeCommand(message.data).then((result) => {
        console.log("[PropFlow] Bulk scrape complete:", result);
        sendResponse(result);
      }).catch((error) => {
        console.error("[PropFlow] Bulk scrape error:", error);
        sendResponse({
          success: false,
          error: error instanceof Error ? error.message : "Unknown error"
        });
      });
      return true;
    }
    if (message.type === "PROPFLOW_PAUSE_BULK_SCRAPE") {
      pauseBulkScrape();
      sendResponse({ success: true });
      return true;
    }
    if (message.type === "PROPFLOW_RESUME_BULK_SCRAPE") {
      resumeBulkScrape();
      sendResponse({ success: true });
      return true;
    }
    if (message.type === "PROPFLOW_CANCEL_BULK_SCRAPE") {
      cancelBulkScrape();
      sendResponse({ success: true });
      return true;
    }
    if (message.type === "PROPFLOW_SCRAPE_SAVED_SEARCHES") {
      const result = scrapeSavedSearches();
      sendResponse(result);
      return true;
    }
    sendResponse({ error: "Unknown message type" });
    return false;
  });
  console.log("[PropFlow] Message listener registered");
  if (isListingPage) {
    console.log("[PropFlow] Detected listing page - injecting button");
    injectRealtorCaButton();
  } else if (isMapPage) {
    console.log("[PropFlow] Detected map page - setting up card buttons and observer");
    injectMapPageButtons();
    setupMapPageObserver();
  } else if (isSavedSearchesPage) {
    console.log("[PropFlow] Detected saved searches page");
    const result = scrapeSavedSearches();
    if (result.success && result.searches) {
      chrome.runtime.sendMessage({
        type: "PROPFLOW_SAVE_SAVED_SEARCHES",
        data: {
          site: "realtor-ca",
          searches: result.searches
        }
      });
    }
  } else {
    console.log("[PropFlow] Unknown Realtor.ca page type:", window.location.pathname);
  }
  console.log("[PropFlow] Realtor.ca content script initialization complete");
}
console.log("[PropFlow] Realtor.ca content script loaded, calling initRealtorCa()");
initRealtorCa();
console.log("[PropFlow] Realtor.ca content script initialization complete");

