function isRealtorComListingPage() {
  const hostname = window.location.hostname;
  const pathname = window.location.pathname;
  return hostname === "www.realtor.com" && (/\d+_[a-z]+_\/$/i.test(pathname) || // /property/12345_abc/
  /^\/property\//i.test(pathname));
}
function scrapeRealtorComListing() {
  try {
    console.log("[PropFlow] Starting Realtor.com scrape...");
    const titleSelectors = [
      '[data-testid="listing-page-title"]',
      'h1[class*="address"]',
      "h1",
      ".address h1"
    ];
    let title = "";
    for (const selector of titleSelectors) {
      const el = document.querySelector(selector);
      if (el?.textContent) {
        title = el.textContent.trim();
        if (title) break;
      }
    }
    const priceSelectors = [
      '[data-testid="listing-price"]',
      '[class*="price"]',
      ".price-item"
    ];
    let price = "";
    for (const selector of priceSelectors) {
      const el = document.querySelector(selector);
      if (el?.textContent) {
        price = el.textContent.trim();
        if (price) break;
      }
    }
    const addressSelectors = [
      '[data-testid="listing-address"]',
      '[class*="address"]',
      ".address"
    ];
    let address = "";
    for (const selector of addressSelectors) {
      const el = document.querySelector(selector);
      if (el?.textContent) {
        address = el.textContent.trim();
        if (address) break;
      }
    }
    const descSelectors = [
      '[data-testid="listing-description"]',
      '[class*="description"]',
      ".description"
    ];
    let description = "";
    for (const selector of descSelectors) {
      const el = document.querySelector(selector);
      if (el?.textContent) {
        description = el.textContent.trim();
        if (description) break;
      }
    }
    const imageSelectors = [
      '[data-testid="photo-gallery"] img',
      'img[class*="gallery"]',
      ".media-gallery img"
    ];
    const images = [];
    for (const selector of imageSelectors) {
      const els = document.querySelectorAll(selector);
      els.forEach((el) => {
        const src = el.src;
        if (src && !images.includes(src) && !src.includes("placeholder")) {
          images.push(src);
        }
      });
      if (images.length > 0) break;
    }
    const detailSelectors = [
      '[data-testid="listing-details"]',
      '[class*="features"]',
      ".key-details"
    ];
    let beds;
    let baths;
    let sqft;
    for (const selector of detailSelectors) {
      const container = document.querySelector(selector);
      if (container) {
        const text = container.textContent || "";
        const bedsMatch = text.match(/(\d+)\s*bed/i);
        if (bedsMatch) beds = parseInt(bedsMatch[1]);
        const bathsMatch = text.match(/(\d+(?:\.\d+)?)\s*bath/i);
        if (bathsMatch) baths = parseFloat(bathsMatch[1]);
        const sqftMatch = text.match(/(\d+(?:,\d+)*)\s*sq?\s*ft/i);
        if (sqftMatch) sqft = parseInt(sqftMatch[1].replace(/,/g, ""));
        if (beds || baths || sqft) break;
      }
    }
    if (!title && !price && !address) {
      return {
        success: false,
        error: "Could not find listing data on this page. Please make sure you are on a property listing page."
      };
    }
    const listing = {
      id: generateListingId2(),
      url: window.location.href,
      title: title || address || "Property Listing",
      price: price || "Contact for Price",
      address: address || "Address not available",
      description,
      beds,
      baths,
      sqft,
      images,
      site: "realtor-com"
    };
    console.log("[PropFlow] Realtor.com scrape successful:", listing);
    return { success: true, listing };
  } catch (error) {
    console.error("[PropFlow] Realtor.com scrape error:", error);
    return {
      success: false,
      error: error instanceof Error ? error.message : "Unknown error occurred while scraping"
    };
  }
}
