    button.style.transform = "translateY(0)";
    button.style.boxShadow = "0 4px 20px rgba(24, 119, 242, 0.4)";
  });
  button.addEventListener("click", async () => {
    try {
      console.log("[PropFlow] Button clicked, scraping...");
      button.textContent = "Scraping...";
      button.style.opacity = "0.7";
      const result = scrapeRealtorComListing();
      if (result.success && result.listing) {
        console.log("[PropFlow] Sending listing to service worker:", result.listing);
        chrome.runtime.sendMessage(
          {
            type: "PROPFLOW_SCRAPE_LISTING",
            data: { listing: result.listing, site: "realtor.com" }
          },
          (response) => {
            console.log("[PropFlow] Service worker response:", response);
            if (chrome.runtime.lastError) {
              console.error("[PropFlow] Runtime error:", chrome.runtime.lastError);
              button.textContent = "Error - Retry";
              button.style.opacity = "1";
            } else if (response?.success) {
              button.textContent = "Saved!";
              button.style.background = "#10b981";
              setTimeout(() => {
                button.textContent = "Post to Facebook";
                button.style.background = "";
              }, 2e3);
            } else {
              button.textContent = "Failed - Retry";
              button.style.background = "#ef4444";
              setTimeout(() => {
                button.textContent = "Post to Facebook";
                button.style.background = "";
              }, 2e3);
            }
          }
        );
      } else {
        console.error("[PropFlow] Scrape failed:", result.error);
        button.textContent = result.error || "Scrape Failed";
        button.style.background = "#ef4444";
        setTimeout(() => {
          button.textContent = "Post to Facebook";
          button.style.background = "";
        }, 3e3);
      }
      button.style.opacity = "1";
    } catch (error) {
      console.error("[PropFlow] Button click error:", error);
      button.textContent = "Error - Retry";
      button.style.background = "#ef4444";
      setTimeout(() => {
        button.textContent = "Post to Facebook";
        button.style.background = "";
      }, 3e3);
    }
  });
  document.body.appendChild(button);
  console.log("[PropFlow] Button injected successfully");
}
